import React from "react";
import Card from "@/components/card";

type HeroProps = {
  children?: React.ReactNode;
};

export default function Hero({ children }: HeroProps) {
  return (
    <section className="max-w-7xl mx-auto px-4 py-20 relative overflow-hidden">
      <div
        className="absolute inset-0 pointer-events-none"
        style={{
          backgroundImage: `
            radial-gradient(circle, #E2E0DC 1px, transparent 1px),
            repeating-linear-gradient(to bottom, rgba(224,220,214,0.06) 0px, rgba(224,220,214,0.06) 0.5px, transparent 0.5px, transparent 50px),
            repeating-linear-gradient(90deg, rgba(224,220,214,0.06) 0px, rgba(224,220,214,0.06) 0.5px, transparent 0.5px, transparent 50px)
          `,
          backgroundSize: "50px 50px, 50px 50px, 50px 50px",
          backgroundPosition: "0 0, 0 0, 0 0",
          zIndex: 0,
        }}
      />

      {/* Left floating pill */}
      <button
        className="absolute left-6 top-12 bg-[#BBE96A] text-black px-3 py-1.5 rounded-full shadow-md hidden sm:inline-flex items-center gap-2"
        aria-hidden
      >
        <span className="text-sm font-medium">DiraSignature</span>
      </button>

      {/* Right floating pill */}
      <button
        className="absolute right-6 top-12 bg-[#F86510] text-white px-3 py-1.5 rounded-full shadow-md hidden sm:inline-flex items-center gap-2"
        aria-hidden
      >
        <span className="text-sm font-medium">Connect wallet</span>
      </button>

      <div className="relative z-10 text-center">
        <h1
          style={{
            fontFamily:
              "'Google Sans','Product Sans', 'Mona Sans', 'Helvetica Neue', Helvetica, Arial, sans-serif",
          }}
          className="text-3xl sm:text-4xl md:text-5xl lg:text-[48px] leading-tight font-semibold text-gray-900"
        >
          Be the Candidate Companies Can’t Ignore
        </h1>

        <p className="mt-6 text-gray-500 max-w-2xl mx-auto text-base sm:text-lg">
          Powering the next generation of Web3 solutions with secure, scalable,
          and seamless technology for a decentralized future.
        </p>

        <div className="mt-8 flex items-center justify-center gap-6">
          <a
            href="#"
            className="inline-flex items-center justify-center bg-[#F86510] text-white px-6 py-3 rounded-full shadow-lg text-sm font-medium hover:shadow-xl transition"
          >
            Try free for 14 days
          </a>

          <div className="flex items-center gap-3">
            <span className="w-10 h-10 inline-flex items-center justify-center bg-white rounded-full shadow">
              
            </span>
            <span className="w-10 h-10 inline-flex items-center justify-center bg-white rounded-full shadow">
              G
            </span>
          </div>
        </div>
      </div>

      {children}

      {/* Fan-style cards at bottom of hero (absolute, overlapping so they don't increase page height) */}
      <div
        className="absolute left-1/2 bottom-6 transform -translate-x-1/2 w-full max-w-4xl"
        aria-hidden
      >
        <div
          className="relative flex items-end justify-center"
          style={{ height: 140 }}
        >
          <div
            style={{
              transform: "rotate(-12deg) translateX(-140px)",
              transformOrigin: "center bottom",
            }}
            className="-ml-6 opacity-95"
          >
            <Card subtitle="liquidity" title="Adoption Indicator" stat="54" />
          </div>

          <div
            style={{
              transform: "rotate(-6deg) translateX(-70px)",
              transformOrigin: "center bottom",
            }}
            className="-ml-4 opacity-95"
          >
            <Card subtitle="expansion" title="Ecosystem Growth" stat="64" />
          </div>

          <div
            style={{
              transform: "rotate(0deg)",
              transformOrigin: "center bottom",
              zIndex: 30,
            }}
            className="mx-2"
          >
            <Card
              subtitle="By total locked value"
              title="Blockchain performance"
              stat="97"
            />
          </div>

          <div
            style={{
              transform: "rotate(6deg) translateX(70px)",
              transformOrigin: "center bottom",
            }}
            className="-mr-4 opacity-95"
          >
            <Card subtitle="Usage" title="Speed" stat="3.2s" />
          </div>

          <div
            style={{
              transform: "rotate(12deg) translateX(140px)",
              transformOrigin: "center bottom",
            }}
            className="-mr-6 opacity-95"
          >
            <Card subtitle="Trade" title="Market" stat="2.9k" />
          </div>
        </div>
      </div>
    </section>
  );
}
