import React from "react";

type CardProps = {
  title?: string;
  subtitle?: string;
  stat?: string | number;
  className?: string;
  style?: React.CSSProperties;
};

export default function Card({
  title,
  subtitle,
  stat,
  className = "",
  style,
}: CardProps) {
  return (
    <div
      className={`w-56 h-36 bg-white rounded-2xl shadow-md p-4 flex flex-col justify-between ${className}`}
      style={{ backfaceVisibility: "hidden", ...style }}
    >
      <div>
        <div className="text-[10px] text-gray-400 uppercase tracking-wider">
          {subtitle}
        </div>
        <div className="mt-1 text-sm font-medium text-gray-800">{title}</div>
      </div>

      <div className="text-xl font-semibold text-gray-900">{stat}</div>
    </div>
  );
}
